sys_variable_value.value:
(function execute(inputs, outputs) {

    outputs.success = false;
    outputs.error_message = "";

    try {

        var cleanId = String(inputs.import_run_sys_id || "").trim();

        var orchestrator = new IncentNowIngestionOrchestrator();
        var result = orchestrator.processRun(cleanId);

        if (result) {
            outputs.success = result.success === true;
            outputs.error_message = result.error_message || "";
        }

    } catch (e) {

        outputs.success = false;
        outputs.error_message = e.toString();
    }

})(inputs, outputs);

